package queryrange

import (
	rpc "github.com/gogo/googleapis/google/rpc"
)

// RPCStatusAdapter bridges the gogo-generated google.rpc.Status to
// wiresmith-generated code: wiresmith cannot embed message types generated by
// another protobuf runtime, so QueryResponse.Status is declared
// google.rpc.Status on the wire but carries this adapter in Go. Wire format is
// identical. Mirrors resultscache.AnyAdapter.
type RPCStatusAdapter rpc.Status

// Status returns the gogo representation. A zero adapter yields nil, matching
// the previous *rpc.Status field shape where absent meant nil.
func (a *RPCStatusAdapter) Status() *rpc.Status {
	if a == nil || (a.Code == 0 && a.Message == "" && len(a.Details) == 0) {
		return nil
	}
	return (*rpc.Status)(a)
}

// FromRPCStatus converts a gogo Status (possibly nil) into the adapter
// representation.
func FromRPCStatus(v *rpc.Status) RPCStatusAdapter {
	if v == nil {
		return RPCStatusAdapter{}
	}
	return RPCStatusAdapter(*v)
}

// SizeWiresmith implements the wiresmith customtype contract.
func (a *RPCStatusAdapter) SizeWiresmith() int { return (*rpc.Status)(a).Size() }

// MarshalWiresmith implements the wiresmith customtype contract.
func (a *RPCStatusAdapter) MarshalWiresmith(buf []byte) (int, error) {
	return (*rpc.Status)(a).MarshalTo(buf)
}

// UnmarshalWiresmith implements the wiresmith customtype contract.
func (a *RPCStatusAdapter) UnmarshalWiresmith(buf []byte) error {
	return (*rpc.Status)(a).Unmarshal(buf)
}

// EqualWiresmith implements the wiresmith customtype contract.
func (a *RPCStatusAdapter) EqualWiresmith(other any) bool {
	o, ok := coerceRPCStatusAdapter(other)
	if !ok {
		return false
	}
	return (*rpc.Status)(a).Equal((*rpc.Status)(o))
}

// CompareWiresmith implements the wiresmith customtype contract.
func (a *RPCStatusAdapter) CompareWiresmith(other any) int {
	o, ok := coerceRPCStatusAdapter(other)
	if !ok {
		return -1
	}
	return (*rpc.Status)(a).Compare((*rpc.Status)(o))
}

func coerceRPCStatusAdapter(other any) (*RPCStatusAdapter, bool) {
	switch o := other.(type) {
	case RPCStatusAdapter:
		return &o, true
	case *RPCStatusAdapter:
		return o, o != nil
	default:
		return nil, false
	}
}
